export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";

  const screen = await callMcpSkill({
    toolId,
    toolName: "find_moderate_probability_bets",
    args: {
      category: "all",
      minPrice: 0.4,
      maxPrice: 0.6,
      minLiquidity: 1000000,
      limit: 10,
      sortBy: "liquidity"
    }
  });

  const opportunities = Array.isArray(screen?.opportunities) ? screen.opportunities : [];
  const shortlist = opportunities.slice(0, 5);

  const analysisBatch = await callMcpSkillsParallel({
    label: "tradability-check",
    calls: shortlist.map((item, idx) => ({
      key: String(idx),
      toolId,
      toolName: "analyze_market_liquidity",
      args: item?.conditionId
        ? { conditionId: item.conditionId }
        : item?.slug
          ? { slug: item.slug }
          : item?.market
            ? { marketQuery: item.market }
            : {}
    }))
  });

  const analyzed = __normalizeToolArrayOutput(analysisBatch.results).map((entry, idx) => {
    const base = shortlist[idx] || {};
    if (entry.status !== "fulfilled") {
      return {
        market: base.market,
        url: base.url,
        currentPrice: base.currentPrice,
        liquidity: base.liquidity,
        conditionId: base.conditionId,
        error: entry.error
      };
    }

    const value = entry.value || {};
    const whaleSell5k = value.whaleCost?.sell5k || {};
    const sell5k = whaleSell5k.estimatedPriceImpact ?? whaleSell5k.slippage ?? null;

    return {
      market: value.market || base.market,
      url: base.url,
      tokenId: value.tokenId,
      currentPrice: value.currentPrice ?? base.currentPrice,
      liquidity: base.liquidity,
      spread: value.spread?.absolute ?? value.spread?.spreadCents ?? null,
      liquidityScore: value.liquidityScore,
      whaleSell5k: whaleSell5k,
      sell5kImpact: sell5k,
      recommendation: value.recommendation,
      conditionId: base.conditionId
    };
  });

  const rankScore = (row) => {
    const scoreMap = { excellent: 4, good: 3, moderate: 2, poor: 1, illiquid: 0 };
    const liq = typeof row.liquidity === "number" ? row.liquidity : 0;
    const ls = scoreMap[row.liquidityScore] ?? 0;
    const spreadPenalty = typeof row.spread === "number" ? row.spread * 100 : 0;
    return liq / 1000000 + ls * 10 - spreadPenalty;
  };

  const ranked = analyzed
    .map((row) => ({
      ...row,
      tradabilityScore: rankScore(row)
    }))
    .sort((a, b) => b.tradabilityScore - a.tradabilityScore);

  return {
    screenedCount: opportunities.length,
    shortlistCount: shortlist.length,
    criteria: {
      minPrice: 0.4,
      maxPrice: 0.6,
      minLiquidity: 1000000
    },
    rankedTradableContracts: ranked,
    source: {
      screening: screen.summary,
      fetchedAt: screen.fetchedAt
    },
    parallelTelemetry: analysisBatch.summary
  };
}

