import { callMcpSkill, callMcpSkillsParallel } from "@/lib/ai/skills/mcp";
import { pickTopSemanticCandidates } from "@/lib/ai/skills/semantic-targeting";

export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";

  const discoveryBatch = await callMcpSkillsParallel({
    label: "polymarket-live-trump-fed-discovery",
    calls: [
      {
        key: "top_markets",
        toolId,
        toolName: "get_top_markets",
        args: {
          limit: 25,
          sortBy: "volume",
          category: "politics",
        },
      },
      {
        key: "trending",
        toolId,
        toolName: "discover_trending_markets",
        args: {
          limit: 25,
          sortBy: "volume",
          category: "politics",
        },
      },
    ],
  });

  const topMarketsResult =
    discoveryBatch.results.find((entry) => entry.key === "top_markets")?.status === "fulfilled"
      ? discoveryBatch.results.find((entry) => entry.key === "top_markets")?.value
      : null;

  const trendingResult =
    discoveryBatch.results.find((entry) => entry.key === "trending")?.status === "fulfilled"
      ? discoveryBatch.results.find((entry) => entry.key === "trending")?.value
      : null;

  const topMarkets = Array.isArray(topMarketsResult?.markets) ? topMarketsResult.markets : [];
  const trendingMarkets = Array.isArray(trendingResult?.trendingMarkets)
    ? trendingResult.trendingMarkets
    : [];

  const combinedCandidates = [...topMarkets, ...trendingMarkets].filter(Boolean);
  const trumpFedCandidates = combinedCandidates.filter((item) => {
    const text = `${item?.title || ""} ${item?.slug || ""} ${item?.eventTitle || ""}`.toLowerCase();
    return text.includes("trump") || text.includes("fed");
  });

  const semanticRanked = pickTopSemanticCandidates({
    target: "live high-volume Trump or Fed-related Polymarket market",
    candidates: trumpFedCandidates.length ? trumpFedCandidates : combinedCandidates,
    requiredTerms: ["trump", "fed"],
    avoidTerms: ["resolved", "expired", "closed"],
    limit: 5,
  });

  const shortlist = Array.isArray(semanticRanked) ? semanticRanked : [];
  const selected = shortlist[0] || trumpFedCandidates[0] || combinedCandidates[0];
  if (!selected) {
    return {
      error: "No suitable live Trump or Fed-related Polymarket market found.",
      discoverySummary: {
        topMarketsCount: topMarkets.length,
        trendingMarketsCount: trendingMarkets.length,
        combinedCandidatesCount: combinedCandidates.length,
      },
    };
  }
  const selectedTitle = String(selected?.title || selected?.market || "");
  const selectedSlug = selected?.slug;
  const selectedConditionId = selected?.conditionId;
  const selectedUrl = selected?.url;
  const selectedCurrentPrice = selected?.currentPrice;
  const selectedVolume24h = selected?.volume24h;
  const selectedLiquidity = selected?.liquidity;

  const directMatchBatch = await callMcpSkillsParallel({
    label: "direct-instrument-and-semantics-check",
    calls: [
      {
        key: "polymarket_efficiency",
        toolId,
        toolName: "check_market_efficiency",
        args: selectedConditionId ? { conditionId: selectedConditionId } : selectedSlug ? { slug: selectedSlug } : {},
      },
      {
        key: "polymarket_rules",
        toolId,
        toolName: "check_market_rules",
        args: selectedConditionId ? { conditionId: selectedConditionId } : selectedSlug ? { slug: selectedSlug } : {},
      },
      {
        key: "kalshi_matches",
        toolId,
        toolName: "polymarket_crossref_kalshi",
        args: {
          title: selectedTitle,
          polymarketSlug: selectedSlug,
          limit: 10,
        },
      },
    ],
  });

  const efficiency =
    directMatchBatch.results.find((entry) => entry.key === "polymarket_efficiency")?.status === "fulfilled"
      ? directMatchBatch.results.find((entry) => entry.key === "polymarket_efficiency")?.value
      : null;

  const rules =
    directMatchBatch.results.find((entry) => entry.key === "polymarket_rules")?.status === "fulfilled"
      ? directMatchBatch.results.find((entry) => entry.key === "polymarket_rules")?.value
      : null;

  const kalshiCrossref =
    directMatchBatch.results.find((entry) => entry.key === "kalshi_matches")?.status === "fulfilled"
      ? directMatchBatch.results.find((entry) => entry.key === "kalshi_matches")?.value
      : null;

  const kalshiResults = Array.isArray(kalshiCrossref?.kalshiResults) ? kalshiCrossref.kalshiResults : [];
  const bestKalshi = kalshiResults.length ? kalshiResults[0] : null;

  const polymarketYesPrice =
    typeof selectedCurrentPrice === "number" ? selectedCurrentPrice : null;
  const polymarketYesPct =
    typeof polymarketYesPrice === "number" ? polymarketYesPrice * 100 : null;
  const kalshiYesPct =
    typeof bestKalshi?.yesPrice === "number" ? bestKalshi.yesPrice : null;

  const semanticsAligned =
    !!bestKalshi &&
    typeof bestKalshi.yesOutcomeMeans === "string" &&
    typeof bestKalshi.noOutcomeMeans === "string" &&
    typeof rules?.description === "string" &&
    typeof rules?.rulesSummary?.resolvesYesIf === "string" &&
    typeof rules?.rulesSummary?.resolvesNoIf === "string";

  const pmImplied = polymarketYesPct;
  const khImplied = kalshiYesPct;
  const gapPoints =
    typeof pmImplied === "number" && typeof khImplied === "number" ? pmImplied - khImplied : null;
  const absGapPoints = typeof gapPoints === "number" ? Math.abs(gapPoints) : null;

  let gapVerdict = "insufficient data";
  if (typeof absGapPoints === "number") {
    if (!semanticsAligned) {
      gapVerdict = "possible semantic mismatch; compare contract wording before treating the gap as real";
    } else if (absGapPoints >= 10) {
      gapVerdict = "likely real gap after semantics are aligned";
    } else {
      gapVerdict = "gap looks modest after semantics are aligned";
    }
  }

  const yesNoSemantics = {
    polymarket: "selectedCurrentPrice is the YES probability/price on Polymarket (so 0.055 means about 5.5% YES, 94.5% NO)",
    kalshi: bestKalshi
      ? `Kalshi YES price is ${typeof bestKalshi.yesPrice === "number" ? bestKalshi.yesPrice : "unknown"}%, with YES meaning ${bestKalshi.yesOutcomeMeans || "unknown"} and NO meaning ${bestKalshi.noOutcomeMeans || "unknown"}`
      : "No Kalshi match found, so YES/NO semantics could not be cross-checked",
    gapMeaning:
      typeof absGapPoints === "number"
        ? `${absGapPoints.toFixed(1)} points apart; ${semanticsAligned ? "the gap is more likely substantive" : "the gap may be a wording mismatch rather than a true price discrepancy"}`
        : "Gap could not be computed from available prices",
  };

  return {
    selectedMarket: {
      title: selectedTitle,
      url: selectedUrl,
      slug: selectedSlug,
      conditionId: selectedConditionId,
      currentPrice: selectedCurrentPrice,
      volume24h: selectedVolume24h,
      liquidity: selectedLiquidity,
    },
    shortlist: shortlist.slice(0, 5).map((item) => ({
      title: item?.title || item?.market,
      slug: item?.slug,
      conditionId: item?.conditionId,
      currentPrice: item?.currentPrice,
      volume24h: item?.volume24h,
      liquidity: item?.liquidity,
    })),
    polymarketAnalysis: {
      efficiency,
      rules,
