      comparisonNote: kalshiCrossref?.comparisonNote,
      searchExhausted: kalshiCrossref?.searchExhausted,
      bestMatch: bestKalshi
        ? {
            title: bestKalshi.title,
            ticker: bestKalshi.ticker,
            url: bestKalshi.url,
            matchScore: bestKalshi.matchScore,
            yesPrice: bestKalshi.yesPrice,
            yesOutcomeMeans: bestKalshi.yesOutcomeMeans,
            noOutcomeMeans: bestKalshi.noOutcomeMeans,
            rules: bestKalshi.rules,
          }
        : null,
      candidates: kalshiResults.map((item) => ({
