        ticker: item.ticker,
        matchScore: item.matchScore,
        yesPrice: item.yesPrice,
        url: item.url,
        yesOutcomeMeans: item.yesOutcomeMeans,
        noOutcomeMeans: item.noOutcomeMeans,
      })),
    },
    gapAnalysis: {
      polymarketYesPrice: polymarketYesPrice,
      polymarketYesPricePercent: pmImplied,
