      },
    ],
  });

  const trending = batch.results.find((r) => r.key === "trending");
  const topLiquidity = batch.results.find((r) => r.key === "topLiquidity");

  const trendingData = trending && trending.status === "fulfilled" ? trending.value : null;
  const liquidityData = topLiquidity && topLiquidity.status === "fulfilled" ? topLiquidity.value : null;

  const topTags = Array.isArray(trendingData?.topTags) ? trendingData.topTags : [];
  const categoriesObj = trendingData?.categories && typeof trendingData.categories === "object" ? trendingData.categories : {};
  const topLiquidByCategory = trendingData?.topLiquidMarketsByCategory && typeof trendingData.topLiquidMarketsByCategory === "object"
    ? trendingData.topLiquidMarketsByCategory
    : {};

  const hottestCategories = Object.entries(categoriesObj)
    .map(([category, value]) => ({
      category,
      value: typeof value === "number" ? value : (value && typeof value.count === "number" ? value.count : null),
      raw: value,
    }))
    .filter((x) => x.value !== null)
    .sort((a, b) => b.value - a.value)
    .slice(0, 5);

  const categoryLiquidityRows = hottestCategories.map((cat) => {
    const markets = Array.isArray(topLiquidByCategory[cat.category]) ? topLiquidByCategory[cat.category] : [];
    const bestMarkets = markets.slice(0, 3).map((m) => ({
      title: m.title,
      slug: m.slug,
      url: m.url,
      liquidity: m.liquidity,
      volume24h: m.volume24h,
    }));
    return {
      category: cat.category,
      hotness: cat.value,
      bestMarkets,
    };
  });

  const overallBestLiquidMarkets = Array.isArray(liquidityData?.markets) ? liquidityData.markets.slice(0, 10) : [];
  const overallTrendingMarkets = Array.isArray(trendingData?.trendingMarkets) ? trendingData.trendingMarkets.slice(0, 10) : [];

  return {
    fetchedAt: {
      trending: trendingData?.fetchedAt || null,
      topLiquidity: liquidityData?.fetchedAt || null,
    },
