    categoryLiquidity: categoryLiquidityRows,
    overallTopLiquidMarkets: overallBestLiquidMarkets.map((m) => ({
      title: m.title,
      slug: m.slug,
      url: m.url,
      liquidity: m.liquidity,
      volume24h: m.volume24h,
      currentPrice: m.currentPrice,
      conditionId: m.conditionId,
    })),
    overallTrendingMarkets: overallTrendingMarkets.map((m) => ({
      title: m.title,
      slug: m.slug,
      url: m.url,
      category: m.category,
      liquidity: m.liquidity,
      volume24h: m.volume24h,
      currentPrice: m.currentPrice,
      whyTrending: m.whyTrending,
      conditionId: m.conditionId,
    })),
  };
}

