    args: {
      category: "politics",
      sortBy: "liquidity",
      limit: 100,
      includeNearResolved: false,
      includeEnded: false
    }
  });

  const markets = Array.isArray(res?.markets) ? res.markets : [];
  const filtered = markets
    .filter((m) => typeof m?.currentPrice === "number" && typeof m?.liquidity === "number")
    .filter((m) => m.currentPrice >= 0.65 && m.currentPrice <= 0.95 && m.liquidity >= 5000)
    .map((m) => {
      const price = m.currentPrice;
      const liquidity = m.liquidity;
      const volatilityProxy = 1 - price; // lower is "cleaner" for high-probability exposure
      const stabilityScore = liquidity * price * (1 - volatilityProxy * 0.6);
      return {
        title: m.title,
        url: m.url,
        slug: m.slug,
        conditionId: m.conditionId,
        currentPrice: m.currentPrice,
        liquidity: m.liquidity,
        volume24h: m.volume24h,
        endDate: m.endDate,
        score: stabilityScore
      };
    })
    .sort((a, b) => {
      if (b.score !== a.score) return b.score - a.score;
      if (b.liquidity !== a.liquidity) return b.liquidity - a.liquidity;
      return b.currentPrice - a.currentPrice;
    });

  return {
    note: "This is from a past query snapshot, not live real-time data.",
